import React from 'react';
import { useForm } from 'react-hook-form';

function RegisterPage() {
    const {register, handleSubmit, formState: { errors }} = useForm();


    function SumbitForm(data) {
        console.log(data); 
        // { username: 'test', email: 'test', password: 'test' }

        const data_of_person = {
            user_name: data.login_name,
            password: data.password
        };

        console.log(data_of_person);
        }

    return (
        <form onSubmit={handleSubmit(SumbitForm)}>
            <input type="text" {...register('login_name')} />
            <input type="password" {...register('password', { required: true })} />
            <input type="password" {...register('confirm_password', { required: true })} />
            {errors.password && <p>Password is required.</p>}
            {errors.confirm_password && <p>Confirm password is required.</p>}
            <input type="submit" />
        </form>
    )
}

export default RegisterPage;
